import React, { useState, useEffect } from 'react';
import api from '../../services/api';

const Dashboard = () => {
  const [stats, setStats] = useState({
    totalUsers: 0,
    totalStores: 0,
    totalRatings: 0
  });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchStats();
  }, []);

  const fetchStats = async () => {
    try {
      const response = await api.get('/stores/admin/dashboard/stats');
      setStats(response.data);
    } catch (error) {
      console.error('Failed to fetch stats:', error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return <div className="container">Loading...</div>;
  }

  return (
    <div className="container">
      <h1 style={{ marginBottom: '30px' }}>Admin Dashboard</h1>
      
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))', gap: '20px' }}>
        <div className="card" style={{ textAlign: 'center' }}>
          <h3>Total Users</h3>
          <p style={{ fontSize: '36px', color: '#667eea', marginTop: '10px' }}>{stats.totalUsers}</p>
        </div>
        
        <div className="card" style={{ textAlign: 'center' }}>
          <h3>Total Stores</h3>
          <p style={{ fontSize: '36px', color: '#764ba2', marginTop: '10px' }}>{stats.totalStores}</p>
        </div>
        
        <div className="card" style={{ textAlign: 'center' }}>
          <h3>Total Ratings</h3>
          <p style={{ fontSize: '36px', color: '#f093fb', marginTop: '10px' }}>{stats.totalRatings}</p>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
